 1→import { useState, useEffect } from "react";
 2→import styles from "./SearchBar.module.scss";
 3→
 4→interface SearchBarProps {
 5→  value: string;
 6→  onChange: (value: string) => void;
 7→  onSubmit?: () => void;
 8→  loading?: boolean;
 9→}
10→
11→const PLACEHOLDERS = [
12→  "Search for React developers...",
13→  "Find senior engineers in NYC...",
14→  "Looking for ML specialists...",
15→  "Discover full-stack talent...",
16→];
17→
18→export function SearchBar({ value, onChange, onSubmit, loading }: SearchBarProps) {
19→  const [placeholderIndex, setPlaceholderIndex] = useState(0);
20→
21→  useEffect(() => {
22→    const interval = setInterval(() => {
23→      setPlaceholderIndex((prev) => (prev + 1) % PLACEHOLDERS.length);
24→    }, 3000);
25→
26→    return () => clearInterval(interval);
27→  }, []);
28→
29→  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
30→    if (e.key === "Enter" && onSubmit) {
31→      onSubmit();
32→    }
33→  };
34→
35→  return (
36→    <div className={styles.wrapper}>
37→      <div className={styles.searchBar}>
38→        <div className={styles.iconWrapper}>
39→          {loading ? (
40→            <svg className={styles.spinner} width="20" height="20" viewBox="0 0 24 24">
41→              <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" fill="none" opacity="0.25" />
42→              <path
43→                fill="currentColor"
44→                d="M12 2a10 10 0 0 1 10 10h-3a7 7 0 0 0-7-7V2z"
45→                opacity="0.75"
46→              />
47→            </svg>
48→          ) : (
49→            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
50→              <circle cx="11" cy="11" r="8" />
51→              <path d="m21 21-4.35-4.35" />
52→            </svg>
53→          )}
54→        </div>
55→        <input
56→          type="text"
57→          className={styles.input}
58→          value={value}
59→          onChange={(e) => onChange(e.target.value)}
60→          onKeyDown={handleKeyDown}
61→          placeholder=""
62→        />
63→        {!value && (
64→          <div className={styles.placeholder} key={placeholderIndex}>
65→            {PLACEHOLDERS[placeholderIndex]}
66→          </div>
67→        )}
68→      </div>
69→    </div>
70→  );
71→}
