 1→import { useState, useRef } from "react";
 2→import styles from "./VideoPlayer.module.scss";
 3→
 4→interface VideoPlayerProps {
 5→  src: string;
 6→  poster?: string;
 7→}
 8→
 9→export function VideoPlayer({ src, poster }: VideoPlayerProps) {
10→  const [playing, setPlaying] = useState(false);
11→  const videoRef = useRef<HTMLVideoElement>(null);
12→
13→  const togglePlay = () => {
14→    if (!videoRef.current) return;
15→
16→    if (playing) {
17→      videoRef.current.pause();
18→    } else {
19→      videoRef.current.play();
20→    }
21→    setPlaying(!playing);
22→  };
23→
24→  return (
25→    <div className={styles.wrapper}>
26→      <video
27→        ref={videoRef}
28→        className={styles.video}
29→        src={src}
30→        poster={poster}
31→        controls={playing}
32→        onPlay={() => setPlaying(true)}
33→        onPause={() => setPlaying(false)}
34→        onEnded={() => setPlaying(false)}
35→      />
36→      {!playing && (
37→        <button className={styles.playButton} onClick={togglePlay}>
38→          <svg width="48" height="48" viewBox="0 0 24 24" fill="currentColor">
39→            <path d="M8 5v14l11-7z" />
40→          </svg>
41→        </button>
42→      )}
43→    </div>
44→  );
45→}
