 1→import { useState } from "react";
 2→
 3→export function useVideoUpload() {
 4→  const [uploading, setUploading] = useState(false);
 5→  const [progress, setProgress] = useState(0);
 6→  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
 7→
 8→  const upload = async (file: File): Promise<string> => {
 9→    setUploading(true);
10→    setProgress(0);
11→
12→    const objectUrl = URL.createObjectURL(file);
13→    setPreviewUrl(objectUrl);
14→
15→    return new Promise((resolve, reject) => {
16→      const xhr = new XMLHttpRequest();
17→
18→      xhr.upload.addEventListener("progress", (e) => {
19→        if (e.lengthComputable) {
20→          const percentComplete = (e.loaded / e.total) * 100;
21→          setProgress(percentComplete);
22→        }
23→      });
24→
25→      xhr.addEventListener("load", () => {
26→        if (xhr.status >= 200 && xhr.status < 300) {
27→          const response = JSON.parse(xhr.responseText);
28→          setUploading(false);
29→          resolve(response.data.url);
30→        } else {
31→          setUploading(false);
32→          reject(new Error(`Upload failed: ${xhr.status}`));
33→        }
34→      });
35→
36→      xhr.addEventListener("error", () => {
37→        setUploading(false);
38→        reject(new Error("Upload failed"));
39→      });
40→
41→      const formData = new FormData();
42→      formData.append("file", file);
43→
44→      xhr.open("POST", "/api/upload");
45→      xhr.send(formData);
46→    });
47→  };
48→
49→  return { upload, uploading, progress, previewUrl };
50→}
